sql:
SELECT DISTINCT p.brand
FROM products p
WHERE p.product_id IN (
    SELECT i.product_id
    FROM inventory i
    WHERE i.quantity > 0
) AND p.product_id IN (
    SELECT o.product_id
    FROM orders o
);

SELECT SUM(quantity) AS total_inventory
FROM inventory
WHERE product_id = 0;

SELECT DISTINCT product_model
FROM products
WHERE is_active = 0;
